module top_module(
    input [3:0] inv_x,y,
    output reg [4:0] z
    );function [4:0] add_two_values;
        input [3:0] inv_x,y;
        begin
            add_two_values = inv_x+y;
        end
    endfunction
    always
        @(inv_x or y)
        begin
            z = add_two_values(inv_x,y);
        end 

endmodule
